# pip install lancedb voyageai
import lancedb
import voyageai
import pandas as pd

_VC = voyageai.Client()


def lancedb_index(texts: list[str], metadatas: list[dict], db_path: str = ".lancedb"):
    db    = lancedb.connect(db_path)  # or "s3://bucket/path"
    vecs  = _VC.embed(texts, model="voyage-3", input_type="document").embeddings
    data  = [
        {"text": text, "vector": vec, **meta}
        for text, vec, meta in zip(texts, vecs, metadatas)
    ]
    if "memories" in db.table_names():
        tbl = db.open_table("memories")
        tbl.add(data)
    else:
        db.create_table("memories", data=data)


def lancedb_search(query: str, k: int = 5, db_path: str = ".lancedb") -> list[dict]:
    db    = lancedb.connect(db_path)
    tbl   = db.open_table("memories")
    q_vec = _VC.embed([query], model="voyage-3", input_type="query").embeddings[0]
    results = tbl.search(q_vec).limit(k).to_list()
    return results

from datetime import datetime, timezone

def expire_old_chunks(client, collection: str, cutoff_ts: float) -> int:
    """Delete all Qdrant points older than cutoff_ts (Unix seconds)."""
    from qdrant_client.models import Filter, FieldCondition, Range
    result = client.delete(
        collection_name=collection,
        points_selector=Filter(
            must=[FieldCondition(key="created_at", range=Range(lt=cutoff_ts))]
        ),
    )
    return result.operation_id

def expire_chroma(collection, cutoff_ts: float) -> None:
    """ChromaDB: fetch IDs by metadata filter, then delete."""
    results = collection.get(
        where={"created_at": {"$lt": cutoff_ts}},
        include=[],          # no embeddings/documents, IDs only
    )
    if results["ids"]:
        collection.delete(ids=results["ids"])

def expire_pinecone(index, namespace: str, cutoff_ts: float) -> None:
    """Pinecone: fetch IDs using filter, delete in batches."""
    response = index.query(
        vector=[0.0] * 1024,  # dummy vector — we only want IDs
        filter={"created_at": {"$lt": cutoff_ts}},
        top_k=1000,
        include_metadata=False,
        namespace=namespace,
    )
    ids = [m.id for m in response.matches]
    if ids:
        index.delete(ids=ids, namespace=namespace)

# LanceDB: SQL DELETE — cleanest syntax
def expire_lancedb(tbl, cutoff_ts: float) -> None:
    tbl.delete(f"created_at < {cutoff_ts}")
